{"code":"import json, re

# Load small sample of publications for 2020-2022 to compute counts to determine EMAs
# We'll query 2020,2021,2022 separately using query_db earlier results keys

# Use the large file for all publications but stream only years 2018-2022 to reduce processing
pubs_path = var_call_Mnu7ZA99v6zlg0eU5qFuAnGn
cpc_defs_path = var_call_YE2zqtqcVqTWgh47MXYr8BqH

with open(cpc_defs_path, 'r', encoding='utf-8') as f:
    cpc_defs = json.load(f)
level5 = set(rec.get('symbol') for rec in cpc_defs if rec.get('symbol'))
symbols_sorted = sorted(level5, key=lambda s: -len(s))

year_re = re.compile(r"(19|20)\d{2}")

def extract_year(text):
    if not text or not isinstance(text, str):
        return None
    m = year_re.search(text)
    if m:
        return int(m.group(0))
    return None

import json

def parse_cpc_field(cpc_str):
    if not cpc_str or not isinstance(cpc_str, str):
        return []
    try:
        lst = json.loads(cpc_str)
        return [d.get('code') for d in lst if isinstance(d, dict) and d.get('code')]
    except Exception:
        return re.findall(r"[A-Z]\d{2}[A-Z]\d*(?:/\d+)?", cpc_str)


def match_code(code):
    if not code:
        return None
    code_no_slash = code.split('/')[0]
    for s in symbols_sorted:
        if code.startswith(s) or code_no_slash.startswith(s):
            return s
    return None

# We'll consider years from 2015 to 2022
years_of_interest = set(range(2015, 2023))
counts = {s: {y:0 for y in years_of_interest} for s in level5}

# Stream parse
with open(pubs_path, 'r', encoding='utf-8') as f:
    buf = ''
    in_obj = False
    brace_count = 0
    while True:
        chunk = f.read(65536)
        if not chunk:
            break
        for ch in chunk:
            if not in_obj:
                if ch == '{':
                    in_obj = True
                    brace_count = 1
                    buf = '{'
                else:
                    continue
            else:
                buf += ch
                if ch == '{':
                    brace_count += 1
                elif ch == '}':
                    brace_count -= 1
                    if brace_count == 0:
                        try:
                            rec = json.loads(buf)
                        except Exception:
                            buf = ''
                            in_obj = False
                            brace_count = 0
                            continue
                        filing = rec.get('filing_date')
                        year = extract_year(filing)
                        if year in years_of_interest:
                            codes = parse_cpc_field(rec.get('cpc'))
                            for code in codes:
                                sym = match_code(code)
                                if sym:
                                    counts[sym][year] += 1
                        buf = ''
                        in_obj = False
                        brace_count = 0

# Compute EMA for each symbol over sorted years
alpha = 0.2
result_syms = []
for sym, yc in counts.items():
    years_sorted = sorted(years_of_interest)
    ema = None
    ema_by_year = {}
    for y in years_sorted:
        c = yc.get(y, 0)
        if ema is None:
            ema = c
        else:
            ema = alpha * c + (1 - alpha) * ema
        ema_by_year[y] = ema
    max_ema = max(ema_by_year.values())
    best_years = [y for y,v in ema_by_year.items() if abs(v-max_ema) < 1e-9]
    if 2022 in best_years:
        result_syms.append(sym)

result = sorted(result_syms)
import json as _json
print("__RESULT__:")
print(_json.dumps(result))"}

